module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    reg [3:0] shift_count;
    reg [7:0] multiplier;
    reg [15:0] accumulator;

    always @(*) begin
        partial_product = 0;
        shift_count = 0;
        multiplier = B;
        accumulator = 0;

        for (int i = 0; i < 8; i = i + 1) begin
            if (multiplier[0]) begin
                partial_product = partial_product + (A << i);
            end
            multiplier = multiplier >> 1;
        end

        product = partial_product;
    end

endmodule
